  ('generalpolice-8b7f1efc-moex-00126', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者正確？', '["警察不當使用警械，因此對人民所生之財產填補應屬於損失補償", "合法行政處分之廢止，乃是基於公益之追求，無損失補償之問題", "對消防人員破門救火行為所為之補償，屬於合法即時強制行為之損失補償，其補償以金錢為限", "行政私法行為在追求公共任務之履行，故亦有可能成立損失補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
